export async function seedCoaTemplates(externalClient?: PrismaClient) {
  const prisma = externalClient ?? getClient();
  const existing = await prisma.coaTemplate.findUnique({ where: { name: "Travel COA" } });
  if (existing) {
    console.log("  ✓ Travel COA template already exists, skipping");
    return;
  }

  await prisma.coaTemplate.create({
    data: {
      name: "Travel COA",
      description: "Standard chart of accounts for Egyptian travel and tourism companies",
      locale: "ar",
      groups: { createMany: { data: TRAVEL_COA_GROUPS.map((g) => ({ ...g })) } },
      accounts: {
        createMany: {
          data: TRAVEL_COA_ACCOUNTS.map((a) => ({
            code: a.code,
            name: a.name,
            accountType: a.accountType,
            reconcile: a.reconcile,
            deprecated: a.deprecated,
            groupName: a.groupName ?? undefined,
          })),
        },
      },
    },
  });

  console.log("  ✓ Travel COA template seeded — 511 accounts, 5 groups");
}

// Run directly if called as script
if (process.argv[1]?.includes("seed-coa-templates")) {
  const client = getClient();
  seedCoaTemplates(client)
    .catch(console.error)
    .finally(() => client.$disconnect());
}